// Recover the over-the-air broadcast symbol from an RTL-SDR u8 IQ capture.
// Symbol is encoded as a CW tone at center + (symbol) kHz. FFT argmax -> symbol.
import { readFileSync } from 'node:fs';

const FS = 2_048_000;       // NESDR sample rate
const N = 1 << 16;          // 65536-pt FFT
const DC_GUARD_HZ = 20_000; // ignore DC spike / LO leak near 0

function loadIQ(path) {
  const u8 = readFileSync(path);
  const re = new Float64Array(N), im = new Float64Array(N);
  for (let k = 0; k < N; k++) {
    const i = (u8[2 * k] - 128) / 128;
    const q = (u8[2 * k + 1] - 128) / 128;
    // Hann window to suppress DC/LO spectral leakage
    const w = 0.5 - 0.5 * Math.cos((2 * Math.PI * k) / (N - 1));
    re[k] = i * w; im[k] = q * w;
  }
  return { re, im };
}

// iterative radix-2 FFT (in place)
function fft(re, im) {
  const n = re.length;
  for (let i = 1, j = 0; i < n; i++) {
    let bit = n >> 1;
    for (; j & bit; bit >>= 1) j ^= bit;
    j ^= bit;
    if (i < j) { [re[i], re[j]] = [re[j], re[i]]; [im[i], im[j]] = [im[j], im[i]]; }
  }
  for (let len = 2; len <= n; len <<= 1) {
    const ang = (-2 * Math.PI) / len;
    const wr = Math.cos(ang), wi = Math.sin(ang);
    for (let i = 0; i < n; i += len) {
      let cwr = 1, cwi = 0;
      for (let k = 0; k < len / 2; k++) {
        const a = i + k, b = i + k + len / 2;
        const tr = re[b] * cwr - im[b] * cwi;
        const ti = re[b] * cwi + im[b] * cwr;
        re[b] = re[a] - tr; im[b] = im[a] - ti;
        re[a] += tr;        im[a] += ti;
        const ncwr = cwr * wr - cwi * wi;
        cwi = cwr * wi + cwi * wr; cwr = ncwr;
      }
    }
  }
}

const binToHz = (k) => (k < N / 2 ? k : k - N) * (FS / N);

function analyze(path) {
  const { re, im } = loadIQ(path);
  fft(re, im);
  let peakK = -1, peakMag = -1;
  for (let k = 0; k < N; k++) {
    const hz = binToHz(k);
    if (Math.abs(hz) < DC_GUARD_HZ) continue;
    const mag = Math.hypot(re[k], im[k]);
    if (mag > peakMag) { peakMag = mag; peakK = k; }
  }
  // magnitude exactly at the expected 66 kHz bin
  const expK = Math.round((66000 / FS) * N);
  const expMag = Math.hypot(re[expK], im[expK]);
  // noise floor = median-ish via mean of non-peak, non-DC bins
  let sum = 0, cnt = 0;
  for (let k = 0; k < N; k++) {
    const hz = binToHz(k);
    if (Math.abs(hz) < DC_GUARD_HZ) continue;
    if (Math.abs(k - peakK) < 8) continue;
    sum += Math.hypot(re[k], im[k]); cnt++;
  }
  const floor = sum / cnt;
  return { peakHz: binToHz(peakK), peakMag, expBinHz: binToHz(expK), expMag, floor };
}

const on = analyze(process.argv[2]);
const off = analyze(process.argv[3]);
const db = (a, b) => 20 * Math.log10(a / b);
const recoveredSymbol = Math.round(Math.abs(on.peakHz) / 1000);

console.log(JSON.stringify({
  overTheAirRecovery: {
    txOn: {
      peakOffsetHz: Math.round(on.peakHz),
      peakSNR_dB: +db(on.peakMag, on.floor).toFixed(2),
      magAt66kHz: +on.expMag.toFixed(2),
    },
    txOff: {
      peakOffsetHz: Math.round(off.peakHz),
      peakSNR_dB: +db(off.peakMag, off.floor).toFixed(2),
      magAt66kHz: +off.expMag.toFixed(2),
    },
    onVsOff_at66kHz_dB: +db(on.expMag, off.expMag).toFixed(2),
    recoveredBroadcastSymbol: recoveredSymbol,
    expectedBroadcastSymbol: 66,
    match: recoveredSymbol === 66,
  },
}, null, 2));
